def icon_dir(size=24):
    return _themed_icon("folder", DIR_SVG, size)

def icon_info(size=24):
    return _themed_icon("dialog-information", INFO_SVG, size)


def app_logo_path() -> str:
    """Return absolute path to the Krokiet logo PNG."""
    from pathlib import Path
    # Try relative to this file first, then absolute project path
    for candidate in [
        Path(__file__).parent.parent.parent / "krokiet" / "icons" / "krokiet_logo.png",
    ]:
        if candidate.exists():
            return str(candidate)
    return ""


def app_icon() -> QIcon:
    """Return the application window icon from the Krokiet logo."""
    path = app_logo_path()
    if path:
        return QIcon(path)
    return QIcon()
